// tests/dashboard/frontend/stores/iteration.test.ts

import { setActivePinia, createPinia } from 'pinia';
import { describe, it, expect, beforeEach, vi } from 'vitest';
import { useIterationStore } from '@/stores/iteration';

describe('Iteration Store', () => {
  beforeEach(() => {
    setActivePinia(createPinia());
  });

  it('初始状态应该正确', () => {
    const store = useIterationStore();
    expect(store.iterations).toEqual([]);
    expect(store.currentIteration).toBeNull();
    expect(store.loading).toBe(false);
  });

  it('应该正确设置当前迭代', () => {
    const store = useIterationStore();
    const mockIteration = { id: 1, status: 'running' };
    store.setCurrentIteration(mockIteration);
    expect(store.currentIteration).toEqual(mockIteration);
  });

  it('loadIterations 应该加载数据', async () => {
    const store = useIterationStore();
    // Mock API call
    await store.loadIterations();
    expect(store.iterations.length).toBeGreaterThan(0);
  });
});
```

